              e.currentTarget.style.background = DESIGN_SYSTEM.colors.secondary;
              e.currentTarget.style.opacity = '1';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = 'none';
              e.currentTarget.style.opacity = '0.7';
            }}
          >
            ⋮
          </button>
        </div>

        {/* Message Options Menu */}
        {showOptions && (
          <MessageOptionsMenu
            msg={msg}
            isOwn={isOwn}
            onClose={() => setShowOptions(false)}
            onCopy={handleCopy}
            onForward={handleForward}
            onReact={handleReact}
            onDelete={handleDelete}
          />
        )}
      </div>
    </div>
  );
}

/* ── Mention Dropdown ─────────────────────────────────────── */
function MentionDropdown({ users, query, selectedIndex, onSelect, onUserSelect, onClose }) {
  if (!users.length) return null;

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      onSelect((selectedIndex + 1) % users.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      onSelect(selectedIndex === 0 ? users.length - 1 : selectedIndex - 1);
    } else if (e.key === 'Escape') {
      e.preventDefault();
      onClose();
    }
  };

  return (
    <div 
      style={{
        position: 'absolute',
        bottom: '100%',
        left: 0,
        right: 0,
        background: 'var(--bg-secondary)',
        border: '1px solid var(--border)',
        borderRadius: 8,
        maxHeight: 200,
        overflowY: 'auto',
        zIndex: 1000,
        marginBottom: 8,
        boxShadow: '0 -4px 16px rgba(0,0,0,0.15)'
      }}
      onKeyDown={handleKeyDown}
    >
      {users.map((user, index) => (
        <div
          key={user.id}
          style={{
            padding: '8px 12px',
            cursor: 'pointer',
            background: index === selectedIndex ? 'var(--bg-active)' : 'transparent',
            display: 'flex',
            alignItems: 'center',
            gap: 10,
            transition: 'background 0.15s'
          }}
          onClick={() => onUserSelect(user)}
          onMouseEnter={() => onSelect(index)}
        >
          <div style={{
            width: 32,
            height: 32,
            borderRadius: '50%',
            background: `${ac(user.full_name)}33`,
            color: ac(user.full_name),
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: 11,
            fontWeight: 700
          }}>
            {ini(user.full_name)}
          </div>
          <div>
            <div style={{ fontSize: 13, fontWeight: 600 }}>{user.full_name}</div>
            <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{user.role}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

